BEGIN;
CREATE TABLE "attendance" ("id" SERIAL PRIMARY KEY, "date" date NOT NULL, "status" varchar(10) NOT NULL, "remarks" varchar(255) NOT NULL, "created_at" timestamp with time zone NOT NULL, "marked_by_id" bigint NULL REFERENCES "users" ("id") DEFERRABLE INITIALLY DEFERRED, "student_id" bigint NOT NULL REFERENCES "students" ("id") DEFERRABLE INITIALLY DEFERRED, "student_class_id" bigint NOT NULL REFERENCES "classes" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "auth_group" ("id" SERIAL PRIMARY KEY, "name" varchar(150) NOT NULL UNIQUE);
CREATE TABLE "auth_group_permissions" ("id" SERIAL PRIMARY KEY, "group_id" integer NOT NULL REFERENCES "auth_group" ("id") DEFERRABLE INITIALLY DEFERRED, "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "auth_permission" ("id" SERIAL PRIMARY KEY, "content_type_id" integer NOT NULL REFERENCES "django_content_type" ("id") DEFERRABLE INITIALLY DEFERRED, "codename" varchar(100) NOT NULL, "name" varchar(255) NOT NULL);
CREATE TABLE "classes" ("id" SERIAL PRIMARY KEY, "section" varchar(10) NOT NULL, "academic_year" varchar(9) NOT NULL, "name" varchar(20) NOT NULL);
CREATE TABLE "django_admin_log" ("id" SERIAL PRIMARY KEY, "object_id" text NULL, "object_repr" varchar(200) NOT NULL, "action_flag" smallint NOT NULL, "change_message" text NOT NULL, "content_type_id" integer NULL REFERENCES "django_content_type" ("id") DEFERRABLE INITIALLY DEFERRED, "user_id" bigint NOT NULL REFERENCES "users" ("id") DEFERRABLE INITIALLY DEFERRED, "action_time" timestamp with time zone NOT NULL);
CREATE TABLE "django_content_type" ("id" SERIAL PRIMARY KEY, "app_label" varchar(100) NOT NULL, "model" varchar(100) NOT NULL);
CREATE TABLE "django_migrations" ("id" SERIAL PRIMARY KEY, "app" varchar(255) NOT NULL, "name" varchar(255) NOT NULL, "applied" timestamp with time zone NOT NULL);
CREATE TABLE "django_session" ("session_key" varchar(40) NOT NULL PRIMARY KEY, "session_data" text NOT NULL, "expire_date" timestamp with time zone NOT NULL);
CREATE TABLE "exams" ("id" SERIAL PRIMARY KEY, "name" varchar(100) NOT NULL, "exam_type" varchar(20) NOT NULL, "start_date" date NOT NULL, "end_date" date NOT NULL, "academic_year" varchar(9) NOT NULL, "is_published" bool NOT NULL, "student_class_id" bigint NOT NULL REFERENCES "classes" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "results" ("id" SERIAL PRIMARY KEY, "marks_obtained" real NOT NULL, "grade" varchar(2) NOT NULL, "remarks" varchar(255) NOT NULL, "created_at" timestamp with time zone NOT NULL, "updated_at" timestamp with time zone NOT NULL, "exam_id" bigint NOT NULL REFERENCES "exams" ("id") DEFERRABLE INITIALLY DEFERRED, "student_id" bigint NOT NULL REFERENCES "students" ("id") DEFERRABLE INITIALLY DEFERRED, "subject_id" bigint NOT NULL REFERENCES "subjects" ("id") DEFERRABLE INITIALLY DEFERRED, "grade_auto" bool NOT NULL);
CREATE TABLE "students" ("id" SERIAL PRIMARY KEY, "roll_number" varchar(20) NOT NULL UNIQUE, "first_name" varchar(100) NOT NULL, "last_name" varchar(100) NOT NULL, "date_of_birth" date NOT NULL, "gender" varchar(10) NOT NULL, "contact_number" varchar(15) NOT NULL, "email" varchar(254) NOT NULL, "address" text NOT NULL, "guardian_name" varchar(200) NOT NULL, "guardian_contact" varchar(15) NOT NULL, "admission_date" date NOT NULL, "profile_photo" varchar(100) NOT NULL, "is_deleted" bool NOT NULL, "created_at" timestamp with time zone NOT NULL, "updated_at" timestamp with time zone NOT NULL, "student_class_id" bigint NOT NULL REFERENCES "classes" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "subjects" ("id" SERIAL PRIMARY KEY, "name" varchar(100) NOT NULL, "code" varchar(20) NOT NULL UNIQUE, "is_language" bool NOT NULL, "max_marks" integer NOT NULL, "pass_marks" integer NOT NULL, "student_class_id" bigint NOT NULL REFERENCES "classes" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "users" ("id" SERIAL PRIMARY KEY, "password" varchar(128) NOT NULL, "last_login" timestamp with time zone NULL, "is_superuser" bool NOT NULL, "username" varchar(150) NOT NULL UNIQUE, "first_name" varchar(150) NOT NULL, "last_name" varchar(150) NOT NULL, "email" varchar(254) NOT NULL, "is_staff" bool NOT NULL, "is_active" bool NOT NULL, "date_joined" timestamp with time zone NOT NULL, "role" varchar(10) NOT NULL, "phone" varchar(15) NOT NULL, "profile_pic" varchar(100) NOT NULL);
CREATE TABLE "users_groups" ("id" SERIAL PRIMARY KEY, "user_id" bigint NOT NULL REFERENCES "users" ("id") DEFERRABLE INITIALLY DEFERRED, "group_id" integer NOT NULL REFERENCES "auth_group" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "users_user_permissions" ("id" SERIAL PRIMARY KEY, "user_id" bigint NOT NULL REFERENCES "users" ("id") DEFERRABLE INITIALLY DEFERRED, "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE UNIQUE INDEX "django_content_type_app_label_model_76bd3d3b_uniq" ON "django_content_type" ("app_label", "model");
CREATE UNIQUE INDEX "auth_group_permissions_group_id_permission_id_0cd325b0_uniq" ON "auth_group_permissions" ("group_id", "permission_id");
CREATE INDEX "auth_group_permissions_group_id_b120cbf9" ON "auth_group_permissions" ("group_id");
CREATE INDEX "auth_group_permissions_permission_id_84c5c92e" ON "auth_group_permissions" ("permission_id");
CREATE UNIQUE INDEX "auth_permission_content_type_id_codename_01ab375a_uniq" ON "auth_permission" ("content_type_id", "codename");
CREATE INDEX "auth_permission_content_type_id_2f476e4b" ON "auth_permission" ("content_type_id");
CREATE UNIQUE INDEX "users_groups_user_id_group_id_fc7788e8_uniq" ON "users_groups" ("user_id", "group_id");
CREATE INDEX "users_groups_user_id_f500bee5" ON "users_groups" ("user_id");
CREATE INDEX "users_groups_group_id_2f3517aa" ON "users_groups" ("group_id");
CREATE UNIQUE INDEX "users_user_permissions_user_id_permission_id_3b86cbdf_uniq" ON "users_user_permissions" ("user_id", "permission_id");
CREATE INDEX "users_user_permissions_user_id_92473840" ON "users_user_permissions" ("user_id");
CREATE INDEX "users_user_permissions_permission_id_6d08dcd2" ON "users_user_permissions" ("permission_id");
CREATE INDEX "django_admin_log_content_type_id_c4bce8eb" ON "django_admin_log" ("content_type_id");
CREATE INDEX "django_admin_log_user_id_c564eba6" ON "django_admin_log" ("user_id");
CREATE INDEX "students_student_class_id_46a996a5" ON "students" ("student_class_id");
CREATE UNIQUE INDEX "attendance_student_id_date_e07e4341_uniq" ON "attendance" ("student_id", "date");
CREATE INDEX "attendance_marked_by_id_d3f29cac" ON "attendance" ("marked_by_id");
CREATE INDEX "attendance_student_id_d55196c7" ON "attendance" ("student_id");
CREATE INDEX "attendance_student_class_id_9b7f8819" ON "attendance" ("student_class_id");
CREATE INDEX "exams_student_class_id_26a8b3af" ON "exams" ("student_class_id");
CREATE UNIQUE INDEX "subjects_code_student_class_id_611ba9c4_uniq" ON "subjects" ("code", "student_class_id");
CREATE INDEX "subjects_student_class_id_f48d00ab" ON "subjects" ("student_class_id");
CREATE INDEX "django_session_expire_date_a5c62663" ON "django_session" ("expire_date");
CREATE UNIQUE INDEX "classes_name_section_aa231816_uniq" ON "classes" ("name", "section");
CREATE UNIQUE INDEX "results_student_id_exam_id_subject_id_bac0c29f_uniq" ON "results" ("student_id", "exam_id", "subject_id");
CREATE INDEX "results_exam_id_ac777c45" ON "results" ("exam_id");
CREATE INDEX "results_student_id_d573a18f" ON "results" ("student_id");
CREATE INDEX "results_subject_id_b73e024d" ON "results" ("subject_id");
COMMIT;